VALUES
  ('heelevel3-53250add-moex-00172', 'heelevel3-53250add', 'heelevel3-53250add-moex-112-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '軍校生甲，因行為失當，遭學校開除學籍。學校擬對甲求償已領取之公費，應循何種方式？', '["以行政處分令甲賠償", "直接依強制執行法聲請強制執行", "向行政法院提起一般給付之訴", "向民事法院提起訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "4bc34ba84b99", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "336", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00173', 'heelevel3-53250add', 'heelevel3-53250add-moex-112-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '多數當事人關於訴訟標的之權利義務關係，在事實上或法律上有同一或同類原因時，有關訴訟程 序之敘述，下列何者錯誤？', '["可以成立共同訴訟，一同擔任原告或被告", "如果當事人分別起訴，法院得命其合併辯論及合併裁判", "共同訴訟之訴訟標的有合一確定必要時，共同訴訟人中一人不利於全體之行為，效力不及於全 體共同訴訟人", "共同訴訟之訴訟標的無論有無合一確定必要，當事人合意停止訴訟後，續行訴訟必須經全體同意"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "4bc34ba84b99", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "336", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00174', 'heelevel3-53250add', 'heelevel3-53250add-moex-112-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '依行政訴訟法規定之都市計畫審查程序，行政法院審查認定都市計畫違法時，下列何者非判決主 文得宣告之內容？', '["都市計畫違法者，宣告無效或違法", "都市計畫發布後始發生違法原因者，應宣告自違法原因發生時起失效", "同一都市計畫中未經原告請求，而與原告請求宣告無效之部分具不可分關係，經法院審查認定 違法者，併宣告撤銷", "依法僅得為違法之宣告者，應宣告其違法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "4bc34ba84b99", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "336", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00175', 'heelevel3-53250add', 'heelevel3-53250add-moex-112-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '某市政府自行興建設置之公立醫院委託私立醫學院經營，因原先所設置之手扶梯未定期保養而故 障，導致病患摔傷。下列敘述何者正確？', '["公共設施委託私人管理，因管理欠缺致人民身體受損害者，負國家賠償責任", "私立醫學院與病患間雖係私法關係，仍不得依民法向醫院求償", "委託屬公法關係，故病患不得依民法向醫院求償", "如病患為外國人者，則無法依國家賠償法求償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "4bc34ba84b99", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "336", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00176', 'heelevel3-53250add', 'heelevel3-53250add-moex-112-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '下列何者非屬政府應給予損失補償之適例？', '["公務員死亡後，所屬機關收回配住之宿舍", "警察依法追捕逃犯，遭逃犯衝撞警車，不慎導致路人甲受重傷", "消防隊為進入火場救火，移除窄巷內之機車，致機車受損", "主管機關就都市計畫道路用地，在徵收之前埋設地下公用管線"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "4bc34ba84b99", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "336", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00177', 'heelevel3-53250add', 'heelevel3-53250add-moex-112-cfe42432', 'sub-heelevel3-53250add-05', NULL, 'essay', '甲女於民國107年9月18日向A市政府警察局提出性騷擾申訴，指稱被乙男
於同年月16日以工作名義邀約其見面並開車接送，在車上以右手牽握甲
女手掌，且對甲女有摟腰及親吻臉頰之動作（下稱系爭行為）。案經A市
政府調查後，提請A市政府性騷擾防治會審議，認定乙男系爭行為性騷擾
事件成立。A市政府乃以B函（下稱原處分）檢附性騷擾事件申訴調查報
告，通知乙男及甲女。乙男不服，提起再申訴、訴願，均遭認定系爭行為
成立性騷擾防治法第2條第2款之性騷擾。乙男不服，提起行政訴訟，聲明：
訴願決定及原處分均撤銷。經丙高等行政法院以D判決撤銷訴願決定及原
處分，A市政府不服，提起上訴。試問：甲女在上訴審中應為何種行政訴
訟行為，以維護自己的權益？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "acba11dafc77", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "336", "s": "0409", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "訴願法與行政訴訟法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00178', 'heelevel3-53250add', 'heelevel3-53250add-moex-112-cfe42432', 'sub-heelevel3-53250add-05', NULL, 'essay', '甲醫療機構以皮膚專科為主要業務，因涉嫌違反醫療法有關規定，被主管
